{
  "name": "Cifras MISSA",
  "description": "Um sistema completo para organização e visualização de cifras musicais voltado para ministérios de música e liturgia de igrejas, com suporte a transposição e setlists."
}

export interface CategoriaLiturgica {
  id: string;
  nome: string;
}

export interface Cifra {
  id: string;
  titulo: string;
  conteudo: string; // Raw text with chords
  tomBase: string;
  tags: string[];
  categorias: string[]; // Array of CategoriaLiturgica IDs
  criadoEm: string;
}

export interface Lista {
  id: string;
  nome: string;
  descricao?: string;
  cifraIds: string[]; // Ordered list of Cifra IDs
  criadoEm: string;
  atualizadoEm: string;
}

export interface AppConfig {
  fontSize: number;
  theme: 'light' | 'dark';
}

export const generateId = (): string => {
  return Math.random().toString(36).substring(2, 11) + Date.now().toString(36);
};

export const normalizeText = (text: string): string => {
  return text
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '');
};

export const formatDate = (dateString: string): string => {
  return new Date(dateString).toLocaleDateString('pt-BR');
};

const chromaticScale = ['C', 'C#', 'D', 'D#', 'E', 'F', 'F#', 'G', 'G#', 'A', 'A#', 'B'];
const flatsMap: Record<string, string> = {
  'Db': 'C#', 'Eb': 'D#', 'Gb': 'F#', 'Ab': 'G#', 'Bb': 'A#',
  'db': 'C#', 'eb': 'D#', 'gb': 'F#', 'ab': 'G#', 'bb': 'A#'
};

// Regex to detect common chord structures
// Matches: [A-G][#,b]?[m,dim,aug,maj,sus]?[0-9,+,(-)]*[/]?[A-G]?[#,b]?
const chordRegex = /\b([A-G][#b]?)(m|dim|aug|maj|sus|add|M)?([0-9]{1,2}|[+])?(\([0-9#b, ]+\))?(\/[A-G][#b]?)?\b/g;

export const transposeChord = (chord: string, steps: number): string => {
  return chord.replace(/([A-G][#b]?)/g, (match) => {
    let note = match;
    // Normalize flats to sharps
    if (flatsMap[note]) note = flatsMap[note];

    const index = chromaticScale.indexOf(note);
    if (index === -1) return match;

    let newIndex = (index + steps) % 12;
    if (newIndex < 0) newIndex += 12;

    return chromaticScale[newIndex];
  });
};

export const transposeText = (text: string, steps: number): string => {
  if (steps === 0) return text;

  // Strategy: Identify lines that likely contain only/mostly chords
  const lines = text.split('\n');
  const transposedLines = lines.map(line => {
    // A simple heuristic: if a line has more spaces/chords than long words, it's a chord line
    const tokens = line.split(/\s+/).filter(t => t.length > 0);
    const chordCount = tokens.filter(t => t.match(chordRegex)).length;

    // If more than 50% of tokens look like chords, transpose the whole line
    if (chordCount > 0 && chordCount / tokens.length > 0.4) {
      return line.replace(chordRegex, (match) => transposeChord(match, steps));
    }
    return line;
  });

  return transposedLines.join('\n');
};

export const isChordLine = (line: string): boolean => {
  const tokens = line.trim().split(/\s+/);
  if (tokens.length === 0) return false;
  const chordCount = tokens.filter(t => t.match(chordRegex)).length;
  return chordCount > 0 && chordCount / tokens.length > 0.5;
};

const KEYS = {
  CIFRAS: 'cifras_missa_cifras',
  LISTAS: 'cifras_missa_listas',
  CATEGORIAS: 'cifras_missa_categorias',
  CONFIG: 'cifras_missa_config'
};

export const storage = {
  get: <T,>(key: keyof typeof KEYS): T | null => {
    try {
      const item = localStorage.getItem(KEYS[key]);
      return item ? JSON.parse(item) : null;
    } catch (e) {
      console.error('Error reading from localStorage', e);
      return null;
    }
  },
  set: <T,>(key: keyof typeof KEYS, value: T): void => {
    try {
      localStorage.setItem(KEYS[key], JSON.stringify(value));
    } catch (e) {
      console.error('Error writing to localStorage', e);
    }
  }
};

import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { Cifra, Lista, CategoriaLiturgica, AppConfig } from '../types/models';
import { storage } from '../services/storageService';
import { INITIAL_SONGS, INITIAL_CATEGORIES } from '../mocks/mockSongs';

interface AppContextType {
  cifras: Cifra[];
  listas: Lista[];
  categorias: CategoriaLiturgica[];
  config: AppConfig;
  addCifra: (cifra: Omit<Cifra, 'id' | 'criadoEm'>) => void;
  updateCifra: (id: string, cifra: Partial<Cifra>) => void;
  deleteCifra: (id: string) => void;
  addLista: (lista: Omit<Lista, 'id' | 'criadoEm' | 'atualizadoEm'>) => void;
  updateLista: (id: string, lista: Partial<Lista>) => void;
  deleteLista: (id: string) => void;
  addCategoria: (nome: string) => void;
  deleteCategoria: (id: string) => void;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

export const AppProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [cifras, setCifras] = useState<Cifra[]>(() => storage.get<Cifra[]>('CIFRAS') || INITIAL_SONGS);
  const [listas, setListas] = useState<Lista[]>(() => storage.get<Lista[]>('LISTAS') || []);
  const [categorias, setCategorias] = useState<CategoriaLiturgica[]>(() => storage.get<CategoriaLiturgica[]>('CATEGORIAS') || INITIAL_CATEGORIES);
  const [config, setConfig] = useState<AppConfig>(() => storage.get<AppConfig>('CONFIG') || { fontSize: 16, theme: 'light' });

  useEffect(() => storage.set('CIFRAS', cifras), [cifras]);
  useEffect(() => storage.set('LISTAS', listas), [listas]);
  useEffect(() => storage.set('CATEGORIAS', categorias), [categorias]);
  useEffect(() => storage.set('CONFIG', config), [config]);

  const addCifra = (data: Omit<Cifra, 'id' | 'criadoEm'>) => {
    const newCifra: Cifra = {
      ...data,
      id: Math.random().toString(36).substring(2, 11),
      criadoEm: new Date().toISOString()
    };
    setCifras(prev => [newCifra, ...prev]);
  };

  const updateCifra = (id: string, data: Partial<Cifra>) => {
    setCifras(prev => prev.map(c => c.id === id ? { ...c, ...data } : c));
  };

  const deleteCifra = (id: string) => {
    setCifras(prev => prev.filter(c => c.id !== id));
    // Also remove from any list
    setListas(prev => prev.map(l => ({
      ...l,
      cifraIds: l.cifraIds.filter(cid => cid !== id)
    })));
  };

  const addLista = (data: Omit<Lista, 'id' | 'criadoEm' | 'atualizadoEm'>) => {
    const now = new Date().toISOString();
    const newLista: Lista = {
      ...data,
      id: Math.random().toString(36).substring(2, 11),
      criadoEm: now,
      atualizadoEm: now
    };
    setListas(prev => [newLista, ...prev]);
  };

  const updateLista = (id: string, data: Partial<Lista>) => {
    setListas(prev => prev.map(l => l.id === id ? { ...l, ...data, atualizadoEm: new Date().toISOString() } : l));
  };

  const deleteLista = (id: string) => {
    setListas(prev => prev.filter(l => l.id !== id));
  };

  const addCategoria = (nome: string) => {
    setCategorias(prev => [...prev, { id: Math.random().toString(36).substring(2, 11), nome }]);
  };

  const deleteCategoria = (id: string) => {
    setCategorias(prev => prev.filter(c => c.id !== id));
  };

  return (
    <AppContext.Provider value={{
      cifras, listas, categorias, config,
      addCifra, updateCifra, deleteCifra,
      addLista, updateLista, deleteLista,
      addCategoria, deleteCategoria
    }}>
      {children}
    </AppContext.Provider>
  );
};

export const useApp = () => {
  const context = useContext(AppContext);
  if (!context) throw new Error('useApp must be used within an AppProvider');
  return context;
};

