---

### 2. O que você deve colocar no Google Apps Script

Substitua todo o conteúdo do seu arquivo no Google Apps Script por este código. Ele está preparado para responder às requisições do frontend corretamente e evitar erros de permissão:

```javascript
// CÓDIGO PARA O GOOGLE APPS SCRIPT (Cifras MISSA)

function doGet(e) {
  const method = e.parameter.method;
  const args = JSON.parse(e.parameter.args || '[]');

  let result;
  try {
    switch(method) {
      case 'testFolderAccess': result = testFolderAccess(args[0]); break;
      case 'getConfiguredFolderId': result = getConfiguredFolderId(); break;
      case 'setConfiguredFolderId': result = setConfiguredFolderId(args[0]); break;
      case 'getAllTextFiles': result = getAllTextFiles(); break;
      case 'getUserLists': result = getUserLists(); break;
      case 'saveUserLists': result = saveUserLists(args[0]); break;
      case 'getUserMeta': result = getUserMeta(); break;
      case 'saveUserMeta': result = saveUserMeta(args[0]); break;
      default: result = { ok: false, error: 'Método não encontrado' };
    }
  } catch (err) {
    result = { ok: false, error: err.toString() };
  }

  // IMPORTANTE: Retorna como JSON puro para o navegador
  return ContentService.createTextOutput(JSON.stringify(result))
    .setMimeType(ContentService.MimeType.JSON);
}

function testFolderAccess(folderId) {
  try {
    const folder = DriveApp.getFolderById(folderId);
    const files = folder.getFilesByType(MimeType.PLAIN_TEXT);
    let count = 0;
    while(files.hasNext()) { files.next(); count++; }
    return { ok: true, name: folder.getName(), fileCount: count };
  } catch (e) {
    return { ok: false, error: 'ID da pasta inválido ou sem permissão: ' + e.message };
  }
}

function setConfiguredFolderId(id) {
  PropertiesService.getUserProperties().setProperty('FOLDER_ID', id);
  return { ok: true };
}

function getConfiguredFolderId() {
  return PropertiesService.getUserProperties().getProperty('FOLDER_ID');
}

function getAllTextFiles() {
  const folderId = getConfiguredFolderId();
  if (!folderId) return { ok: false, error: 'Pasta não configurada' };

  const folder = DriveApp.getFolderById(folderId);
  const files = folder.getFilesByType(MimeType.PLAIN_TEXT);
  const results = [];

  while (files.hasNext()) {
    const file = files.next();
    results.push({
      id: file.getId(),
      nome: file.getName().replace('.txt', ''),
      conteudo: file.getBlob().getDataAsString(),
      ultimaAtualizacao: file.getLastUpdated().toISOString()
    });
  }
  return results;
}

function saveUserLists(lists) {
  const folderId = getConfiguredFolderId();
  const folder = DriveApp.getFolderById(folderId);
  const fileName = 'eac_listas.json';
  const files = folder.getFilesByName(fileName);
  const content = JSON.stringify(lists);

  if (files.hasNext()) {
    files.next().setContent(content);
  } else {
    folder.createFile(fileName, content, MimeType.JSON);
  }
  return { ok: true };
}

function saveUserMeta(meta) {
  const folderId = getConfiguredFolderId();
  const folder = DriveApp.getFolderById(folderId);
  const fileName = 'eac_meta.json';
  const files = folder.getFilesByName(fileName);
  const content = JSON.stringify(meta);

  if (files.hasNext()) {
    files.next().setContent(content);
  } else {
    folder.createFile(fileName, content, MimeType.JSON);
  }
  return { ok: true };
}

function getUserLists() {
  return readJsonFile('eac_listas.json') || [];
}

function getUserMeta() {
  return readJsonFile('eac_meta.json') || {};
}

function readJsonFile(name) {
  const folderId = getConfiguredFolderId();
  if (!folderId) return null;
  const folder = DriveApp.getFolderById(folderId);
  const files = folder.getFilesByName(name);
  if (files.hasNext()) {
    return JSON.parse(files.next().getBlob().getDataAsString());
  }
  return null;
}
```

### Passo a passo para o Google Apps Script:
1.  Cole o código acima no editor.
2.  Clique no ícone de **disquete (Salvar)**.
3.  Clique em **Implantar > Nova implantação**.
4.  Selecione **App da Web**.
5.  Em "Quem pode acessar", selecione **Qualquer pessoa** (Anyonoe).
6.  Clique em **Implantar**.
7.  **IMPORTANTE**: Copie o URL que termina em `/exec` e cole nas Configurações do seu app.

Com isso, o erro de comunicação deve desaparecer!

