import { Link } from 'react-router-dom';
import { Plus, Trash2, Calendar, Music, ArrowLeft, ChevronRight, Clock, List, Cloud, CloudOff, RefreshCw, CheckCircle2 } from 'lucide-react';
import { useApp } from '../context/AppContext';
import { formatDate } from '../utils/stringUtils';

const Listas: React.FC = () => {
  const { listas, deleteLista, isSyncing, saveToDrive, config } = useApp();
  const [syncFeedback, setSyncFeedback] = useState<{show: boolean, success?: boolean}>({ show: false });

  const handleManualBackup = async () => {
    setSyncFeedback({ show: true });
    const success = await saveToDrive();
    setSyncFeedback({ show: true, success });
    setTimeout(() => setSyncFeedback({ show: false }), 3000);
  };

  return (
    <div className="max-w-5xl mx-auto py-8 px-4 space-y-6">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div className="flex items-center gap-3">
          <Link to="/" className="p-2 hover:bg-gray-100 rounded-full transition-colors text-gray-500">
            <ArrowLeft size={24} />
          </Link>
          <div className="flex flex-col">
            <h1 className="text-2xl font-bold text-gray-900">Minhas Listas</h1>
            {config.lastSync && (
              <span className="text-[10px] text-gray-400 font-bold uppercase tracking-wider">Último backup: {new Date(config.lastSync).toLocaleString()}</span>
            )}
          </div>
        </div>
        <div className="flex gap-2">
          <button 
            onClick={handleManualBackup}
            disabled={isSyncing}
            className="flex items-center justify-center gap-2 bg-gray-100 hover:bg-gray-200 text-gray-700 px-4 py-2.5 rounded-xl font-bold transition-all disabled:opacity-50"
            title="Fazer backup manual para o Drive"
          >
            {isSyncing ? <RefreshCw size={18} className="animate-spin" /> : <Cloud size={18} />}
            <span className="hidden sm:inline">Backup nuvem</span>
          </button>
          <Link 
            to="/listas/nova"
            className="flex items-center justify-center gap-2 bg-amber-500 hover:bg-amber-600 text-white px-6 py-2.5 rounded-xl font-bold transition-all shadow-md shadow-amber-200"
          >
            <Plus size={20} /> Nova Lista
          </Link>
        </div>
      </div>

      {syncFeedback.show && (
        <div className={`p-3 rounded-xl border flex items-center justify-center gap-2 animate-in fade-in zoom-in duration-300 ${
          syncFeedback.success === undefined ? 'bg-blue-50 border-blue-100 text-blue-600' :
          syncFeedback.success ? 'bg-green-50 border-green-100 text-green-600' : 'bg-red-50 border-red-100 text-red-600'
        }`}>
          {syncFeedback.success === undefined ? <RefreshCw className="animate-spin" size={16} /> :
           syncFeedback.success ? <CheckCircle2 size={16} /> : <CloudOff size={16} />}
          <span className="text-sm font-bold">
            {syncFeedback.success === undefined ? 'Sincronizando listas...' :
             syncFeedback.success ? 'Listas salvas no Google Drive!' : 'Falha ao salvar no Drive.'}
          </span>
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        {listas.map(lista => (
          <div key={lista.id} className="group bg-white rounded-2xl border border-gray-100 p-6 shadow-sm hover:shadow-md transition-all relative">
            <div className="flex justify-between items-start mb-4">
              <div className="space-y-1">
                <Link to={`/listas/${lista.id}`} className="text-xl font-bold text-gray-900 hover:text-amber-600 transition-colors flex items-center gap-2">
                  {lista.nome}
                  {/* FIX: Wrapping Cloud icon in span to avoid TS error with 'title' prop */}
                  <span title="Sincronizado">
                    <Cloud size={14} className="text-green-500 opacity-60" />
                  </span>
                </Link>
                <div className="flex items-center gap-3 text-xs text-gray-400 font-medium uppercase tracking-wider">
                  <span className="flex items-center gap-1"><Calendar size={14}/> {formatDate(lista.criadoEm)}</span>
                  <span className="flex items-center gap-1"><Music size={14}/> {lista.cifraIds.length} músicas</span>
                </div>
              </div>
              <button 
                onClick={() => confirm('Excluir esta lista?') && deleteLista(lista.id)}
                className="p-2 text-gray-300 hover:text-red-500 transition-colors"
              >
                <Trash2 size={20} />
              </button>
            </div>

            {lista.descricao && (
              <p className="text-gray-500 text-sm line-clamp-2 mb-6">{lista.descricao}</p>
            )}

            <div className="flex gap-2">
              <Link 
                to={`/listas/${lista.id}`}
                className="flex-1 bg-amber-50 hover:bg-amber-100 text-amber-700 py-3 rounded-xl font-bold text-center text-sm transition-colors flex items-center justify-center gap-2"
              >
                Modo Tocar <ChevronRight size={16} />
              </Link>
            </div>
          </div>
        ))}

        {listas.length === 0 && (
          <div className="col-span-full py-20 text-center space-y-4">
            <div className="bg-amber-50 w-20 h-20 rounded-full flex items-center justify-center mx-auto text-amber-300">
              <List size={40} />
            </div>
            <div className="space-y-1">
              <p className="text-gray-900 font-bold text-lg">Nenhuma lista criada ainda</p>
              <p className="text-gray-500">Crie uma nova lista para organizar suas apresentações.</p>
            </div>
            <Link 
              to="/listas/nova"
              className="inline-flex items-center gap-2 bg-amber-500 hover:bg-amber-600 text-white px-8 py-3 rounded-xl font-bold transition-all shadow-lg shadow-amber-200"
            >
              Criar minha primeira lista
            </Link>
          </div>
        )}
      </div>
    </div>
  );
};

export default Listas;

import React, { createContext, useContext, useState, useEffect, ReactNode, useRef } from 'react';
import { Cifra, Lista, CategoriaLiturgica, AppConfig } from '../types/models';
import { storage } from '../services/storageService';
import { googleDriveService } from '../services/googleDriveService';

interface SyncResult {
  success: boolean;
  count?: number;
  newCount?: number;
  updatedCount?: number;
  keptCount?: number;
  error?: string;
}

interface AppContextType {
  cifras: Cifra[];
  listas: Lista[];
  categorias: CategoriaLiturgica[];
  config: AppConfig;
  isSyncing: boolean;
  syncFromDrive: () => Promise<SyncResult>;
  saveToDrive: () => Promise<boolean>;
  addCifra: (cifra: Omit<Cifra, 'id' | 'criadoEm'>) => void;
  updateCifra: (id: string, cifra: Partial<Cifra>) => void;
  deleteCifra: (id: string) => void;
  addLista: (lista: Omit<Lista, 'id' | 'criadoEm' | 'atualizadoEm'>) => void;
  updateLista: (id: string, lista: Partial<Lista>) => void;
  deleteLista: (id: string) => void;
  addCategoria: (nome: string) => void;
  deleteCategoria: (id: string) => void;
  updateConfig: (config: Partial<AppConfig>) => void;
  clearAllData: () => void;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

export const AppProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [cifras, setCifras] = useState<Cifra[]>(() => storage.get<Cifra[]>('CIFRAS') || []);
  const [listas, setListas] = useState<Lista[]>(() => storage.get<Lista[]>('LISTAS') || []);
  const [categorias, setCategorias] = useState<CategoriaLiturgica[]>(() => storage.get<CategoriaLiturgica[]>('CATEGORIAS') || []);
  const [config, setConfig] = useState<AppConfig>(() => storage.get<AppConfig>('CONFIG') || { fontSize: 16, theme: 'light' });
  const [isSyncing, setIsSyncing] = useState(false);
  const syncTimeoutRef = useRef<number | null>(null);

  useEffect(() => storage.set('CIFRAS', cifras), [cifras]);
  useEffect(() => storage.set('LISTAS', listas), [listas]);
  useEffect(() => storage.set('CATEGORIAS', categorias), [categorias]);
  useEffect(() => storage.set('CONFIG', config), [config]);

  const scheduleDriveSave = () => {
    if (syncTimeoutRef.current) window.clearTimeout(syncTimeoutRef.current);
    syncTimeoutRef.current = window.setTimeout(() => {
      saveToDrive();
    }, 3000);
  };

  const clearAllData = () => {
    setCifras([]);
    setListas([]);
    setCategorias([]);
    localStorage.removeItem('cifras_missa_cifras');
    localStorage.removeItem('cifras_missa_listas');
    localStorage.removeItem('cifras_missa_categorias');
  };

  const syncFromDrive = async (): Promise<SyncResult> => {
    setIsSyncing(true);
    let newCount = 0;
    let updatedCount = 0;
    let keptCount = 0;

    try {
      const driveFiles = await googleDriveService.getAllTextFiles();
      const driveListas = await googleDriveService.getUserLists();

      if (Array.isArray(driveFiles)) {
        setCifras(prev => {
          const updatedCifras = [...prev];

          driveFiles.forEach((file: any) => {
            const index = updatedCifras.findIndex(c => c.driveId === file.id || c.titulo === file.nome);

            // Lógica Incremental: 
            // Só atualizamos se o arquivo for novo OU se a data de modificação for diferente
            const needsUpdate = index === -1 || updatedCifras[index].ultimaAtualizacao !== file.ultimaAtualizacao;

            if (needsUpdate) {
              const cifraData: Cifra = {
                id: index >= 0 ? updatedCifras[index].id : Math.random().toString(36).substring(2, 11),
                driveId: file.id,
                titulo: file.nome,
                conteudo: file.conteudo,
                tomBase: index >= 0 ? updatedCifras[index].tomBase : 'C',
                categorias: index >= 0 ? updatedCifras[index].categorias : [],
                tags: index >= 0 ? updatedCifras[index].tags : [],
                criadoEm: index >= 0 ? updatedCifras[index].criadoEm : new Date().toISOString(),
                ultimaAtualizacao: file.ultimaAtualizacao
              };

              if (index >= 0) {
                updatedCifras[index] = cifraData;
                updatedCount++;
              } else {
                updatedCifras.push(cifraData);
                newCount++;
              }
            } else {
              keptCount++;
            }
          });
          return updatedCifras;
        });
      }

      if (Array.isArray(driveListas) && driveListas.length > 0) {
        setListas(driveListas);
      }

      const totalCount = driveFiles?.length || 0;
      setConfig(prev => ({ ...prev, lastSync: new Date().toISOString() }));

      return { 
        success: true, 
        count: totalCount,
        newCount,
        updatedCount,
        keptCount
      };
    } catch (e: any) {
      console.error('Erro ao sincronizar do Drive:', e);
      return { success: false, error: e.message || 'Erro de conexão com o Drive.' };
    } finally {
      setIsSyncing(false);
    }
  };

  const saveToDrive = async (): Promise<boolean> => {
    if (!config.gasApiUrl) return false;
    setIsSyncing(true);
    try {
      await googleDriveService.saveUserLists(listas);
      const meta = { 
        metaPorCifraId: cifras.reduce((acc, c) => ({
          ...acc, 
          [c.id]: { tom: c.tomBase, categorias: c.categorias }
        }), {})
      };
      await googleDriveService.saveUserMeta(meta);
      return true;
    } catch (e) {
      console.error('Erro ao salvar no Drive:', e);
      return false;
    } finally {
      setIsSyncing(false);
    }
  };

  const addCifra = (data: Omit<Cifra, 'id' | 'criadoEm'>) => {
    const newCifra: Cifra = {
      ...data,
      id: Math.random().toString(36).substring(2, 11),
      criadoEm: new Date().toISOString()
    };
    setCifras(prev => [newCifra, ...prev]);
  };

  const updateCifra = (id: string, data: Partial<Cifra>) => {
    setCifras(prev => prev.map(c => c.id === id ? { ...c, ...data } : c));
  };

  const deleteCifra = (id: string) => {
    setCifras(prev => prev.filter(c => c.id !== id));
    setListas(prev => prev.map(l => ({
      ...l,
      cifraIds: l.cifraIds.filter(cid => cid !== id)
    })));
    scheduleDriveSave();
  };

  const addLista = (data: Omit<Lista, 'id' | 'criadoEm' | 'atualizadoEm'>) => {
    const now = new Date().toISOString();
    const newLista: Lista = {
      ...data,
      id: Math.random().toString(36).substring(2, 11),
      criadoEm: now,
      atualizadoEm: now
    };
    setListas(prev => [newLista, ...prev]);
    scheduleDriveSave();
  };

  const updateLista = (id: string, data: Partial<Lista>) => {
    setListas(prev => prev.map(l => l.id === id ? { ...l, ...data, atualizadoEm: new Date().toISOString() } : l));
    scheduleDriveSave();
  };

  const deleteLista = (id: string) => {
    setListas(prev => prev.filter(l => l.id !== id));
    scheduleDriveSave();
  };

  const addCategoria = (nome: string) => {
    setCategorias(prev => [...prev, { id: Math.random().toString(36).substring(2, 11), nome }]);
  };

  const deleteCategoria = (id: string) => {
    setCategorias(prev => prev.filter(c => c.id !== id));
  };

  const updateConfig = (newConfig: Partial<AppConfig>) => {
    setConfig(prev => ({ ...prev, ...newConfig }));
  };

  return (
    <AppContext.Provider value={{
      cifras, listas, categorias, config, isSyncing,
      syncFromDrive, saveToDrive,
      addCifra, updateCifra, deleteCifra,
      addLista, updateLista, deleteLista,
      addCategoria, deleteCategoria, updateConfig, clearAllData
    }}>
      {children}
    </AppContext.Provider>
  );
};

export const useApp = () => {
  const context = useContext(AppContext);
  if (!context) throw new Error('useApp must be used within an AppProvider');
  return context;
};

import React, { useState, useMemo, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { Search, Plus, Trash2, ArrowLeft, RefreshCw, Cloud, X, CheckCircle2, AlertCircle, Info } from 'lucide-react';
import { useApp } from '../context/AppContext';
import { normalizeText } from '../utils/stringUtils';

const Biblioteca: React.FC = () => {
  const { cifras, deleteCifra, addCifra, categorias, syncFromDrive, isSyncing } = useApp();
  const [search, setSearch] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [syncStatus, setSyncStatus] = useState<{
    show: boolean, 
    success?: boolean, 
    msg: string,
    stats?: { new: number, updated: number, kept: number }
  }>({ show: false, msg: '' });

  const [newSong, setNewSong] = useState({
    titulo: '',
    tomBase: 'C',
    conteudo: '',
    selectedCategorias: [] as string[]
  });

  useEffect(() => {
    if (syncStatus.show && syncStatus.success) {
      const timer = setTimeout(() => setSyncStatus(prev => ({ ...prev, show: false })), 8000);
      return () => clearTimeout(timer);
    }
  }, [syncStatus.show, syncStatus.success]);

  const filteredCifras = useMemo(() => {
    const term = normalizeText(search);
    return cifras.filter(c => 
      normalizeText(c.titulo).includes(term) || 
      c.tags.some(t => normalizeText(t).includes(term))
    );
  }, [cifras, search]);

  const handleSync = async () => {
    setSyncStatus({ show: true, msg: 'Analisando biblioteca no Drive...' });
    try {
      const result = await syncFromDrive();
      if (result.success) {
        setSyncStatus({ 
          show: true, 
          success: true, 
          msg: `Sincronização inteligente concluída!`,
          stats: {
            new: result.newCount || 0,
            updated: result.updatedCount || 0,
            kept: result.keptCount || 0
          }
        });
      } else {
        setSyncStatus({ show: true, success: false, msg: result.error || 'Erro desconhecido na sincronização.' });
      }
    } catch (err: any) {
      setSyncStatus({ show: true, success: false, msg: err.message || 'Falha na comunicação com o servidor.' });
    }
  };

  const handleAddSong = () => {
    if (!newSong.titulo || !newSong.conteudo) return;
    addCifra({
      titulo: newSong.titulo,
      tomBase: newSong.tomBase,
      conteudo: newSong.conteudo,
      categorias: newSong.selectedCategorias,
      tags: []
    });
    setNewSong({ titulo: '', tomBase: 'C', conteudo: '', selectedCategorias: [] });
    setIsModalOpen(false);
  };

  const toggleCategory = (id: string) => {
    setNewSong(prev => ({
      ...prev,
      selectedCategorias: prev.selectedCategorias.includes(id)
        ? prev.selectedCategorias.filter(x => x !== id)
        : [...prev.selectedCategorias, id]
    }));
  };

  return (
    <div className="max-w-5xl mx-auto py-8 px-4 space-y-6">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div className="flex items-center gap-3">
          <Link to="/" className="p-2 hover:bg-gray-100 rounded-full text-gray-500">
            <ArrowLeft size={24} />
          </Link>
          <h1 className="text-2xl font-bold text-gray-900">Biblioteca</h1>
        </div>
        <div className="flex gap-2">
          <button 
            onClick={handleSync}
            disabled={isSyncing}
            className="flex items-center justify-center gap-2 bg-gray-100 hover:bg-gray-200 text-gray-700 px-4 py-2.5 rounded-xl font-bold transition-all disabled:opacity-50 relative"
            title="Sincronizar com Drive"
          >
            <RefreshCw size={20} className={isSyncing ? 'animate-spin' : ''} />
            <span className="hidden sm:inline">{isSyncing ? 'Analisando...' : 'Sincronizar'}</span>
          </button>
          <button 
            onClick={() => setIsModalOpen(true)}
            className="flex items-center justify-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-6 py-2.5 rounded-xl font-bold transition-all shadow-md shadow-blue-200"
          >
            <Plus size={20} /> Nova Cifra
          </button>
        </div>
      </div>

      {syncStatus.show && (
        <div className={`flex flex-col gap-3 p-4 rounded-2xl border animate-in slide-in-from-top duration-300 relative ${
          syncStatus.success === undefined ? 'bg-blue-50 border-blue-100 text-blue-700' :
          syncStatus.success ? 'bg-green-50 border-green-100 text-green-700' : 
          'bg-red-50 border-red-100 text-red-700'
        }`}>
          <div className="flex items-start gap-3">
            <div className="mt-0.5">
              {syncStatus.success === undefined ? <RefreshCw className="animate-spin" size={20} /> :
               syncStatus.success ? <CheckCircle2 size={20} /> : <AlertCircle size={20} />}
            </div>
            <div className="flex-1 pr-8">
              <span className="font-bold text-sm block">{syncStatus.msg}</span>
              {syncStatus.stats && (
                <div className="flex flex-wrap gap-4 mt-2">
                   <div className="flex items-center gap-1.5">
                      <span className="w-2 h-2 rounded-full bg-blue-400"></span>
                      <span className="text-xs font-medium">Novas: <strong>{syncStatus.stats.new}</strong></span>
                   </div>
                   <div className="flex items-center gap-1.5">
                      <span className="w-2 h-2 rounded-full bg-amber-400"></span>
                      <span className="text-xs font-medium">Atualizadas: <strong>{syncStatus.stats.updated}</strong></span>
                   </div>
                   <div className="flex items-center gap-1.5">
                      <span className="w-2 h-2 rounded-full bg-green-400"></span>
                      <span className="text-xs font-medium">Sem alterações: <strong>{syncStatus.stats.kept}</strong></span>
                   </div>
                </div>
              )}
            </div>
            <button 
              onClick={() => setSyncStatus(prev => ({ ...prev, show: false }))}
              className="absolute right-3 top-3 p-1 hover:bg-black/5 rounded-full"
            >
              <X size={16} />
            </button>
          </div>
        </div>
      )}

      <div className="relative">
        <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={20} />
        <input 
          type="text"
          placeholder="Buscar música..."
          className="w-full pl-12 pr-4 py-3.5 bg-white border border-gray-200 rounded-2xl shadow-sm focus:ring-2 focus:ring-blue-500 outline-none"
          value={search}
          onChange={(e) => setSearch(e.target.value)}
        />
      </div>

      {cifras.length === 0 && !isSyncing && (
        <div className="py-20 text-center space-y-4 bg-white rounded-3xl border border-dashed border-gray-200">
           <Cloud className="mx-auto text-gray-300" size={48} />
           <p className="text-gray-500 font-medium">Sua biblioteca está vazia.</p>
           <button onClick={handleSync} className="text-blue-600 font-bold hover:underline">Sincronizar agora</button>
        </div>
      )}

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
        {filteredCifras.map(cifra => (
          <div key={cifra.id} className="group bg-white rounded-2xl border border-gray-100 p-5 shadow-sm hover:shadow-md transition-all">
            <Link to={`/cifra/${cifra.id}`} className="block space-y-3">
              <div className="flex justify-between items-start">
                <span className="inline-block bg-blue-50 text-blue-600 text-xs font-bold px-2 py-1 rounded">
                  {cifra.tomBase}
                </span>
                <div className="flex items-center gap-2">
                   {cifra.driveId && (
                     <span title="Sincronizado com Drive">
                       <Cloud size={14} className="text-green-500" />
                     </span>
                   )}
                   <button 
                    onClick={(e) => {
                      e.preventDefault();
                      if(confirm('Excluir esta cifra?')) deleteCifra(cifra.id);
                    }}
                    className="p-1 text-gray-300 hover:text-red-500 transition-colors"
                   >
                    <Trash2 size={16} />
                   </button>
                </div>
              </div>
              <h3 className="text-lg font-bold text-gray-900 group-hover:text-blue-600 truncate">
                {cifra.titulo}
              </h3>
              <div className="flex flex-wrap gap-1">
                {cifra.categorias.map(catId => {
                  const cat = categorias.find(x => x.id === catId);
                  return cat ? <span key={catId} className="text-[10px] bg-gray-100 text-gray-500 px-2 py-0.5 rounded-full">{cat.nome}</span> : null;
                })}
              </div>
            </Link>
          </div>
        ))}
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm overflow-y-auto">
          <div className="bg-white w-full max-w-2xl rounded-3xl shadow-2xl flex flex-col max-h-[90vh]">
            <div className="p-6 border-b border-gray-100 flex items-center justify-between">
              <h2 className="text-xl font-bold text-gray-900">Nova Cifra</h2>
              <button onClick={() => setIsModalOpen(false)} className="p-2 hover:bg-gray-100 rounded-full text-gray-400">
                <X size={20} />
              </button>
            </div>

            <div className="flex-1 overflow-y-auto p-6 space-y-6">
              <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                <div className="md:col-span-3">
                  <label className="block text-xs font-bold text-gray-400 uppercase mb-1">Título da Música</label>
                  <input 
                    type="text"
                    className="w-full px-4 py-2.5 border border-gray-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500"
                    placeholder="Ex: Hino de Louvor"
                    value={newSong.titulo}
                    onChange={e => setNewSong({...newSong, titulo: e.target.value})}
                  />
                </div>
                <div>
                  <label className="block text-xs font-bold text-gray-400 uppercase mb-1">Tom</label>
                  <select 
                    className="w-full px-4 py-2.5 border border-gray-200 rounded-xl outline-none focus:ring-2 focus:ring-blue-500"
                    value={newSong.tomBase}
                    onChange={e => setNewSong({...newSong, tomBase: e.target.value})}
