  const [search, setSearch] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [syncResult, setSyncResult] = useState<{
    show: boolean, 
    success?: boolean, 
    msg: string,
    stats?: { new: number, updated: number, kept: number }
  }>({ show: false, msg: '' });

  const [newSong, setNewSong] = useState({
