declare const google: any;

const extractFolderId = (input: string): string => {
  if (!input) return '';
  if (input.includes('folders/')) {
    const parts = input.split('folders/')[1].split('?')[0].split('/');
    return parts[0].trim();
  }
  return input.trim();
};

let currentRuntimeApiUrl = '';

const run = async (methodName: string, ...args: any[]): Promise<any> => {
  // 1. Ambiente Google Apps Script (se embutido)
  if (typeof google !== 'undefined' && google.script && google.script.run) {
    return new Promise((resolve, reject) => {
      google.script.run
        .withSuccessHandler(resolve)
        .withFailureHandler(reject)[methodName](...args);
    });
  }

  // 2. Ambiente Externo
  if (!currentRuntimeApiUrl) {
    throw new Error('URL da API não configurada. Vá em Ajustes.');
  }

  try {
    const isSaveMethod = methodName.startsWith('save') || methodName.startsWith('set');
    let response;

    /**
     * IMPORTANTE PARA EVITAR ERRO DE CORS:
     * Não definimos nenhum Header customizado (como Content-Type: application/json).
     * Isso mantém a requisição como 'Simple Request', evitando o preflight OPTIONS do navegador,
     * que é onde o Google Script costuma falhar se não estiver configurado corretamente.
     */
    if (isSaveMethod) {
      response = await fetch(currentRuntimeApiUrl, {
        method: 'POST',
        mode: 'cors',
        redirect: 'follow',
        body: JSON.stringify({
          method: methodName,
          args: args
        })
      });
    } else {
      const urlWithParams = new URL(currentRuntimeApiUrl);
      urlWithParams.searchParams.append('method', methodName);
      urlWithParams.searchParams.append('args', JSON.stringify(args));

      response = await fetch(urlWithParams.toString(), {
        method: 'GET',
        mode: 'cors',
        redirect: 'follow'
      });
    }

    if (!response.ok) {
      throw new Error(`Erro de rede: ${response.status}. Verifique a URL.`);
    }

    const data = await response.json();
    if (data && data.ok === false) throw new Error(data.error || 'Erro interno no Script.');
    return data;

  } catch (e: any) {
    console.error('Fetch error:', e);
    // Erros de "Failed to fetch" são tipicamente CORS ou Rede
    if (e.message.includes('fetch') || e.name === 'TypeError') {
      throw new Error('Falha na Conexão (CORS/Rede). Verifique se o Script está publicado para "Qualquer Pessoa" (Anyone) e se a URL termina em /exec');
    }
    throw e;
  }
};

