 * Este serviço gerencia a comunicação com o Google Apps Script.
 * Otimizado para máxima compatibilidade com as políticas de CORS do Google.
 */

declare const google: any;

const cleanUrl = (url: string): string => {
  return url.trim().replace(/[\n\r]/g, '');
};

const extractFolderId = (input: string): string => {
  if (!input) return '';
  const trimmed = input.trim();
  if (trimmed.includes('folders/')) {
    const parts = trimmed.split('folders/')[1].split('?')[0].split('/');
    return parts[0].trim();
  }
  return trimmed;
};

let currentRuntimeApiUrl = '';

const run = async (methodName: string, ...args: any[]): Promise<any> => {
  // 1. Ambiente Google Apps Script (se embutido no editor)
  if (typeof google !== 'undefined' && google.script && google.script.run) {
    return new Promise((resolve, reject) => {
      google.script.run
        .withSuccessHandler(resolve)
        .withFailureHandler(reject)[methodName](...args);
    });
  }

  // 2. Ambiente Externo (Vercel/Web)
  if (!currentRuntimeApiUrl) {
    throw new Error('URL da API não configurada.');
  }

  const targetUrl = cleanUrl(currentRuntimeApiUrl);

  try {
    const isSaveMethod = methodName.startsWith('save') || methodName.startsWith('set');
    let response;

    /**
     * ESTRATÉGIA ANTI-BLOQUEIO:
     * Para evitar o 'Failed to fetch', não podemos enviar NENHUM header customizado.
     * O Google Apps Script redireciona a requisição, e headers extras quebram esse fluxo.
     */
    if (isSaveMethod) {
      // POST simplificado
      response = await fetch(targetUrl, {
        method: 'POST',
        mode: 'cors',
        redirect: 'follow',
        // Enviamos como texto simples para evitar Preflight OPTIONS
        body: JSON.stringify({
          method: methodName,
          args: args
        })
      });
    } else {
      // GET simplificado
      const url = new URL(targetUrl);
      url.searchParams.append('method', methodName);
      url.searchParams.append('args', JSON.stringify(args));

      response = await fetch(url.toString(), {
        method: 'GET',
        mode: 'cors',
        redirect: 'follow'
      });
    }

    if (!response.ok) {
      throw new Error(`HTTP ${response.status}`);
    }

    const text = await response.text();
    try {
      const data = JSON.parse(text);
      if (data && data.ok === false) throw new Error(data.error || 'Erro no Script');
      return data;
    } catch (e) {
      // Se não for JSON, o Google pode ter retornado uma página de erro/login
      if (text.includes('google-signin') || text.includes('login')) {
        throw new Error('Erro de Autenticação. Verifique se o Script está publicado para "Qualquer Pessoa" (Anyone).');
      }
      throw new Error('O servidor não retornou um JSON válido. Verifique a URL /exec');
    }

  } catch (e: any) {
    console.error('Fetch detail:', e);
    if (e.message.includes('fetch') || e.name === 'TypeError') {
      throw new Error(
        'Falha Crítica de Conexão. Verifique:\n' +
        '1. Se a URL termina exatamente em /exec\n' +
        '2. Se você publicou como "Qualquer pessoa" (Anyone)\n' +
        '3. Se o código do seu Script no Google está atualizado (veja o guia nos Ajustes).'
      );
    }
    throw e;
  }
};

